from collections import defaultdict
from datetime import datetime

def appliquer_regles(evenements):
    """Applique des règles de corrélation et génère des alertes."""
    alertes = []

    # Index par IP et type
    par_ip = defaultdict(lambda: defaultdict(list))
    for evt in evenements:
        par_ip[evt["ip"]][evt["type"]].append(evt)

    for ip, types in par_ip.items():
        # Règle 1 : Brute Force SSH (>= 3 échecs)
        echecs = types.get("ssh_fail", [])
        if len(echecs) >= 3:
            alertes.append({
                "ip": ip, "regle": "BRUTE_FORCE_SSH",
                "severite": "HAUTE",
                "details": f"{len(echecs)} tentatives échouées"
            })

        # Règle 2 : Scan + Connexion réussie = Intrusion probable
        if types.get("port_scan") and types.get("ssh_success"):
            alertes.append({
                "ip": ip, "regle": "POSSIBLE_INTRUSION",
                "severite": "CRITIQUE",
                "details": "Scan de ports suivi d'une connexion réussie"
            })

        # Règle 3 : Connexion + Téléchargement de fichier
        if types.get("ssh_success") and types.get("file_download"):
            fichiers = [e["details"] for e in types["file_download"]]
            alertes.append({
                "ip": ip, "regle": "POST_EXPLOITATION",
                "severite": "CRITIQUE",
                "details": f"Fichiers téléchargés : {fichiers}"
            })

    return alertes

alerts = appliquer_regles(EVENEMENTS)
for a in alerts:
    print(f"[{a['severite']}] {a['regle']} depuis {a['ip']}: {a['details']}")
